using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page-fetching tools for the research agent.
/// Uses DuckDuckGo HTML search (no API key required).
/// </summary>
public sealed partial class WebSearchService
{
    private readonly HttpClient _httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0 (compatible)" },
            { "Accept", "text/html" },
        },
    };

    [Description("Searches the web for the given query and returns a list of results with titles, URLs, and snippets. Use this to find information about a topic.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encodedQuery}";

            var request = new HttpRequestMessage(HttpMethod.Get, url);
            var response = await _httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var results = ParseSearchResults(html);

            if (results.Count == 0)
            {
                return $"No results found for: {query}";
            }

            return $"Search results for \"{query}\":\n\n" + string.Join("\n---\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    [Description("Fetches and extracts the text content of a web page. Use this to read the full content of a specific URL found in search results.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            var response = await _httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = ExtractTextFromHtml(html);

            const int maxLength = 4000;
            if (text.Length > maxLength)
            {
                text = text[..maxLength] + "\n\n[Content truncated at 4000 characters]";
            }

            return $"Content from {url}:\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch {url}: {ex.Message}";
        }
    }

    private static List<string> ParseSearchResults(string html)
    {
        var results = new List<string>();

        var linkMatches = ResultLinkRegex().Matches(html);
        var snippetMatches = ResultSnippetRegex().Matches(html);

        for (int i = 0; i < Math.Min(linkMatches.Count, 5); i++)
        {
            var rawUrl = linkMatches[i].Groups[1].Value;
            var title = StripHtml(linkMatches[i].Groups[2].Value);
            var snippet = i < snippetMatches.Count
                ? StripHtml(snippetMatches[i].Groups[1].Value)
                : "(no snippet)";

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var actualUrl = ExtractActualUrl(rawUrl);

            results.Add($"[{i + 1}] {title}\n    URL: {actualUrl}\n    {snippet}");
        }

        return results;
    }

    private static string ExtractActualUrl(string duckDuckGoUrl)
    {
        // DDG URLs look like: //duckduckgo.com/l/?uddg=https%3A%2F%2F...&rut=...
        var match = UddgParamRegex().Match(duckDuckGoUrl);
        if (match.Success)
        {
            return Uri.UnescapeDataString(match.Groups[1].Value);
        }

        return duckDuckGoUrl.StartsWith("//")
            ? "https:" + duckDuckGoUrl
            : duckDuckGoUrl;
    }

    private static string ExtractTextFromHtml(string html)
    {
        // Remove script and style blocks
        var cleaned = ScriptStyleRegex().Replace(html, " ");
        // Remove HTML tags
        cleaned = HtmlTagRegex().Replace(cleaned, " ");
        // Decode HTML entities
        cleaned = WebUtility.HtmlDecode(cleaned);
        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ").Trim();

        return cleaned;
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, "");
        return WebUtility.HtmlDecode(text).Trim();
    }

    [GeneratedRegex("""<a rel="nofollow" class="result__a" href="([^"]+)"[^>]*>(.+?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultLinkRegex();

    [GeneratedRegex("""<a class="result__snippet"[^>]*>(.+?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultSnippetRegex();

    [GeneratedRegex("""uddg=([^&]+)""")]
    private static partial Regex UddgParamRegex();

    [GeneratedRegex("""<(script|style)[^>]*>.*?</\1>""", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex("""<[^>]+>""")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex("""\s+""")]
    private static partial Regex WhitespaceRegex();
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides an in-memory note-taking tool for the research agent
/// to record and review findings during research.
/// </summary>
public sealed class NoteService
{
    private readonly List<Note> _notes = [];

    [Description("Records a research note. Use this to save important findings, facts, or quotes discovered during research.")]
    public string TakeNote(
        [Description("A short title or label for the note")] string title,
        [Description("The detailed content of the note, including source URL if available")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieves all research notes taken so far. Use this to review collected findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var formatted = _notes.Select((n, i) =>
            $"[Note {i + 1}] {n.Title}\n{n.Content}\n(Recorded at {n.Timestamp:HH:mm:ss UTC})");

        return $"Research Notes ({_notes.Count} total):\n\n" + string.Join("\n\n", formatted);
    }

    public int Count => _notes.Count;

    private sealed record Note(string Title, string Content, DateTime Timestamp);
}

