using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides an in-memory note-taking tool for the research agent
/// to record and review findings during research.
/// </summary>
public sealed class NoteService
{
    private readonly List<Note> _notes = [];

    [Description("Records a research note. Use this to save important findings, facts, or quotes discovered during research.")]
    public string TakeNote(
        [Description("A short title or label for the note")] string title,
        [Description("The detailed content of the note, including source URL if available")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieves all research notes taken so far. Use this to review collected findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var formatted = _notes.Select((n, i) =>
            $"[Note {i + 1}] {n.Title}\n{n.Content}\n(Recorded at {n.Timestamp:HH:mm:ss UTC})");

        return $"Research Notes ({_notes.Count} total):\n\n" + string.Join("\n\n", formatted);
    }

    public int Count => _notes.Count;

    private sealed record Note(string Title, string Content, DateTime Timestamp);
}

