var searchService = new WebSearchService();
var noteService = new NoteService();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(searchService.SearchWebAsync),
    AIFunctionFactory.Create(searchService.FetchPageAsync),
    AIFunctionFactory.Create(noteService.TakeNote),
    AIFunctionFactory.Create(noteService.GetNotes),
};

